import React, { useState } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { Users, LayoutDashboard, User, Home, LogOut, MoreVertical, Menu, X, Shield, Bell } from 'lucide-react';
import { useAuth } from '../context/AuthContext';

const Navbar = () => {
  const location = useLocation();
  const { user, logout, token } = useAuth();
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const isLoggedIn = !!token && !!user;

  const NavLink = ({ to, children, icon: Icon }) => {
    const isActive = location.pathname === to;
    return (
      <Link
        to={to}
        onClick={() => setIsMenuOpen(false)}
        className={`flex items-center space-x-2 px-6 py-2 rounded-full transition-all duration-300 ${
          isActive 
            ? 'bg-primary-600 text-white shadow-lg' 
            : 'text-gray-400 hover:text-white hover:bg-white/5'
        }`}
      >
        <Icon size={18} />
        <span className="font-bold uppercase text-xs tracking-widest">{children}</span>
      </Link>
    );
  };

  return (
    <motion.nav 
      initial={{ y: -100 }}
      animate={{ y: 0 }}
      className="fixed top-0 left-0 right-0 z-50 px-6 py-4"
    >
      <div className="max-w-7xl mx-auto glass flex items-center justify-between px-8 py-3 rounded-full relative overflow-hidden shadow-2xl">
        <div className="absolute top-0 left-0 w-32 h-full bg-primary-600/5 -z-10 translate-x-[-100%] group-hover:translate-x-0 transition-transform"></div>

        {/* Left Section: Three Dots Menu */}
        <div className="flex items-center space-x-4">
          <button 
            onClick={() => setIsMenuOpen(!isMenuOpen)}
            className="p-2.5 bg-white/5 rounded-xl hover:bg-white/10 text-gray-400 hover:text-primary-400 transition-all border border-white/10"
          >
            <MoreVertical size={20} />
          </button>

          <Link to="/" className="flex items-center space-x-2">
            <div className="w-10 h-10 bg-gradient-to-br from-primary-400 to-primary-700 rounded-xl flex items-center justify-center shadow-lg transform rotate-6 hover:rotate-0 transition-all duration-300">
              <span className="text-white font-bold text-xl uppercase">B</span>
            </div>
            <span className="text-2xl font-bold font-poppins tracking-tight hidden md:block uppercase">
              Buddy<span className="text-primary-400 font-extrabold text-sm ml-1 italic tracking-widest">Up</span>
            </span>
          </Link>
        </div>

        {/* Center: Desktop Navigation */}
        <div className="hidden md:flex items-center space-x-2">
          <NavLink to="/" icon={Home}>Home</NavLink>
          {isLoggedIn && (
            <>
              <NavLink to="/find-buddies" icon={Users}>Find Buddies</NavLink>
              <NavLink to="/dashboard" icon={LayoutDashboard}>Dashboard</NavLink>
              <NavLink to="/profile" icon={User}>Profile</NavLink>
            </>
          )}
        </div>

        {/* Right Section: Auth or Notification */}
        <div className="flex items-center space-x-2 md:space-x-4">
          {isLoggedIn ? (
             <div className="flex items-center space-x-2">
                <button className="p-2.5 text-gray-400 hover:text-primary-400 hover:bg-white/5 rounded-full transition-all">
                  <Bell size={18} />
                </button>
                <button 
                  onClick={logout}
                  className="hidden md:flex items-center space-x-2 px-6 py-2.5 text-red-400 hover:text-white hover:bg-red-600/20 rounded-full border border-red-500/10 transition-all font-black uppercase text-xs tracking-widest"
                >
                  <LogOut size={16} />
                </button>
             </div>
          ) : (
            <div className="flex items-center space-x-4">
              <Link to="/login" className="text-gray-400 hover:text-white transition-all font-black uppercase text-xs tracking-widest hidden sm:block">Login</Link>
              <Link to="/signup" className="btn-primary py-2.5 px-6 font-black uppercase text-xs tracking-widest shadow-2xl">Join Now</Link>
            </div>
          )}
        </div>
      </div>

      {/* Slide-out Overlay Menu */}
      <AnimatePresence>
        {isMenuOpen && (
          <motion.div 
            initial={{ opacity: 0, x: -300 }}
            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0, x: -300 }}
            className="fixed top-24 left-6 w-72 glass-card p-6 shadow-2xl rounded-3xl z-[100]"
          >
             <div className="flex flex-col space-y-4">
                <NavLink to="/" icon={Home}>Home</NavLink>
                {isLoggedIn && (
                  <>
                    <NavLink to="/find-buddies" icon={Users}>Find Buddies</NavLink>
                    <NavLink to="/dashboard" icon={LayoutDashboard}>Dashboard</NavLink>
                    <NavLink to="/profile" icon={User}>Profile</NavLink>
                    <button className="w-full mt-8 py-3 bg-red-600/10 hover:bg-red-600/20 text-red-500 border border-red-500/20 rounded-xl transition-all font-black uppercase text-xs tracking-widest" onClick={logout}>Sign Out</button>
                  </>
                )}
                {!isLoggedIn && (
                  <>
                    <NavLink to="/login" icon={Shield}>Login</NavLink>
                    <NavLink to="/signup" icon={Rocket}>Get Started</NavLink>
                  </>
                )}
             </div>
          </motion.div>
        )}
      </AnimatePresence>
    </motion.nav>
  );
};

export default Navbar;
